def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0 or item <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        priority = 0
        temp_sum = 0
        if ratio > 8:
            for a in range(8, 0, -1):
                for b in range(1, a+4):
                    inner_val = ((ratio - a) ** 4) / (b + a * 0.7)
                    temp_sum += inner_val * np.sin(ratio * b * np.pi / (a + 2))
                    if temp_sum > 1000:
                        temp_sum *= 0.8
            priority += temp_sum ** 1.8 + np.exp(ratio - 7) * np.cos(ratio*2.1)
        elif 5 < ratio <= 8:
            for x in range(1, int(np.floor(ratio)) + 5):
                for y in range(1, x + 4):
                    val = ((ratio - x) ** 2.5) * np.cos(ratio * y * 2) / (y + 0.7)
                    priority += np.tanh(val) * 1.5
            priority += np.log1p(ratio) * 9 - np.tanh(ratio - 5) * 3
        elif 2 <= ratio <= 5:
            s1, s2 = 0, 0
            for n in range(1, 15):
                s1 += ((ratio - 2) ** n) / (n * 2.3) * np.sin(n * ratio)
            for m in range(1, 8):
                s2 += np.cos(m * ratio * 1.7) / (m ** 1.4)
            priority = s1 * s2 - np.log(ratio + 0.1) * 5 + np.tanh(5 * (5 - ratio)) * 2
        elif 1 <= ratio < 2:
            partial_sum = 0
            for k in range(1, 20):
                partial_sum += ((2 - ratio) ** k) / (k**2 + 1) * np.cos(k * ratio * 3)
            if cap < item * 1.2:
                penalty = np.sqrt(item / (cap + 0.3)) * 5
            else:
                penalty = np.sin(30 * ratio) * 3
            priority = partial_sum + penalty + np.exp(-2 / (ratio + 0.02))
            for p in range(1, 6):
                priority += np.sin(p * ratio * i * 0.7) * ((ratio - 1) ** p) / (p * 0.9)
        elif 0.5 <= ratio < 1:
            s = 0
            for q in range(1, 18):
                s += ((1 - ratio) ** q) / (q * 3.5) * np.sin(q * item * 1.1)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(cap + 4) * 1.7
            else:
                priority /= (np.sqrt(cap + 2) + 3)
            for r in range(1, 8):
                priority += ((1 - ratio) ** r) * np.cos(r * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for t in range(1, 14):
                s += ((0.5 - ratio) ** t) / (t * 4.5) * np.cos(t * ratio * 3)
            priority = s + 3 / (cap + 5)
            if int(item * 1.7) % 6 == 0:
                priority *= 3
            else:
                priority /= 3
            if cap < item * 0.3:
                priority += np.log1p(item * cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 5
            for u in range(1, 9):
                priority += ((0.5 - ratio) ** u) / (u * 8) * np.sin(item * u * 0.9)
        else:
            s = 0
            for v in range(1, 13):
                s += ((0.2 - ratio) ** v) / (v * 6) * np.cos(v * item * 1.2)
            priority = s + 4 / (cap + 6)
            if int(item * 0.8) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if cap < item * 0.1:
                priority += np.log1p(item * cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 6
            for w in range(1, 10):
                priority += ((0.2 - ratio) ** w) / (w * 9) * np.sin(item * w * 1.1)
        if cap < item * 0.7:
            priority += np.log1p(item ** 3 * cap) * 7
        elif cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx_shift in range(1, 6):
            if (i + idx_shift) % 5 == 0:
                priority += np.sin(ratio * (i + idx_shift) * 1.3) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx_shift) * 1.3) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.7
        if (i * int(item)) % 7 == 0:
            priority += np.exp(-abs(cap - item)) * 3
        priorities[i] = priority
    return priorities
